require_once __DIR__.'/../../app/Core/Config.php';require_once __DIR__.'/../../app/Core/Db.php';require_once __DIR__.'/../../app/Core/Settings.php';require_once __DIR__.'/../../app/Core/Security.php';require_once __DIR__.'/../../app/Core/Csrf.php';require_once __DIR__.'/../../app/Core/Auth.php';require_once __DIR__.'/../../app/Services/Repository.php';require_once __DIR__.'/../../app/Services/LicenseService.php';
use App\Core\Config;use App\Core\Db;use App\Core\Settings;use App\Core\Security;use App\Core\Csrf;use App\Core\Auth;use App\Services\Repository;use App\Services\LicenseService;
Config::load(__DIR__.'/../../config/config.php');session_name((string)Config::get('security.session_name','NSGUARDSESSID'));session_start();$repo=new Repository();
function fl(?string $m=null,string $t='ok'){if($m!==null){$_SESSION['flash']=[$m,$t];return;} $f=$_SESSION['flash']??null; unset($_SESSION['flash']); return $f;} function go(string $p){header('Location: /admin/?page='.$p);exit;} function post(){if($_SERVER['REQUEST_METHOD']!=='POST')throw new RuntimeException('Método inválido');Csrf::verify();} function apply_cmd(string $which='all'){ $cmd=(string)Config::get('commands.'.($which==='dns'?'apply_dns':($which==='firewall'?'apply_firewall':'apply'))); exec($cmd.' 2>&1',$out,$code); if($code!==0) throw new RuntimeException('Falha ao aplicar: '.implode("\n",$out)); return trim(implode("\n",$out)); }
function hostbase(){return preg_replace('/:\d+$/','',$_SERVER['HTTP_HOST']??'127.0.0.1')?:'127.0.0.1';}
function headx(string $title){$u=Auth::user();$p=$_GET['page']??'dashboard';echo '<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>'.Security::e($title).'</title><link rel="stylesheet" href="/assets/app.css"></head><body>'; if($u){$items=['dashboard'=>'Dashboard','zones'=>'Zonas DNS','blocks'=>'Bloqueios','firewall'=>'Firewall NS','settings'=>'Configuração'];echo '<aside class="sidebar"><div class="brand"><span class="brand-icon">NS</span><div><b>NS Guard</b><small>Ubuntu 24.04 + BIND9</small></div></div><nav>';foreach($items as $k=>$v)echo '<a class="'.($p===$k?'active':'').'" href="/admin/?page='.$k.'">'.Security::e($v).'</a>';echo '</nav><form class="logout" method="post"><input type="hidden" name="act" value="logout">'.Csrf::field().'<button>Sair</button></form></aside><main class="main"><header class="topbar"><div><h1>'.Security::e($title).'</h1><p>'.Security::e($u['name']).' · '.Security::e($u['role']).'</p></div><div class="top-actions"><a class="btn" target="_blank" href="http://'.Security::e(hostbase()).':80/">80</a><a class="btn" target="_blank" href="http://'.Security::e(hostbase()).':89/">89</a><a class="btn" href="/admin/change-password.php">Alterar senha</a></div></header>'; $ls=(new LicenseService())->status(false); if(!$ls['valid']) echo '<div class="flash error"><b>Licença:</b> '.Security::e($ls['message']).'. A porta 80 não redireciona enquanto não validar.</div>'; } else echo '<main class="auth-main">'; if($f=fl())echo '<div class="flash '.Security::e($f[1]).'">'.Security::e($f[0]).'</div>';}
function foot(){echo '</main></body></html>';}
function card($t,$v,$h=''){echo '<div class="stat-card"><span>'.Security::e($t).'</span><strong>'.Security::e($v).'</strong><small>'.Security::e($h).'</small></div>';}
try{$act=$_POST['act']??''; if($act==='login'){post(); if(Auth::login($_POST['email']??'',$_POST['password']??'')){fl('Login efetuado');go('dashboard');} fl('Login inválido','error');go('login');} if($act==='logout'){post();Auth::logout();go('login');}$page=$_GET['page']??'dashboard'; if($page==='login'){headx('Login');echo '<section class="login-card"><h1>NS Guard</h1><p>Painel na porta 8087. DNS na 53, redirect 80 e banner 89.</p><form method="post"><input type="hidden" name="act" value="login">'.Csrf::field().'<label>Email<input type="email" name="email" required></label><label>Senha<input type="password" name="password" required></label><button class="primary">Entrar</button></form></section>';foot();exit;} Auth::requireLogin();
if($_SERVER['REQUEST_METHOD']==='POST'){post();switch($act){case 'settings':Settings::set('sinkhole_ip',trim($_POST['sinkhole_ip']??''));Settings::set('redirect_url',Security::urlTemplate($_POST['redirect_url']??''));Settings::set('license_key',trim($_POST['license_key']??''));Settings::set('license_url',trim($_POST['license_url']??''));Settings::set('block_notice_title',trim($_POST['block_notice_title']??''));Settings::set('block_notice_message',trim($_POST['block_notice_message']??''));fl('Configuração salva. '.apply_cmd('dns'));go('settings');case 'check_license':$s=(new LicenseService())->status(true);fl($s['message'],$s['valid']?'ok':'error');go('settings');case 'add_block':$repo->addBlock($_POST['domain']??'',$_POST['category']??'malware',$_POST['action']??'redirect',$_POST['reason']??'');fl('Bloqueio salvo. '.apply_cmd('dns'));go('blocks');case 'toggle_block':$repo->toggleBlock((int)$_POST['id'],(int)$_POST['active']===1);fl('Bloqueio atualizado. '.apply_cmd('dns'));go('blocks');case 'del_block':$repo->deleteBlock((int)$_POST['id']);fl('Bloqueio removido. '.apply_cmd('dns'));go('blocks');case 'add_zone':$repo->addZone($_POST['zone']??'',(int)($_POST['ttl']??3600));fl('Zona salva. '.apply_cmd('dns'));go('zones');case 'toggle_zone':$repo->toggleZone((int)$_POST['id'],(int)$_POST['active']===1);fl('Zona atualizada. '.apply_cmd('dns'));go('zones');case 'del_zone':$repo->deleteZone((int)$_POST['id']);fl('Zona removida. '.apply_cmd('dns'));go('zones');case 'add_record':$repo->addRecord((int)$_POST['zone_id'],$_POST['name']??'@',$_POST['type']??'A',(int)($_POST['ttl']??3600),$_POST['content']??'');fl('Record salvo. '.apply_cmd('dns'));go('records&zone_id='.(int)$_POST['zone_id']);case 'toggle_record':$repo->toggleRecord((int)$_POST['id'],(int)$_POST['active']===1);fl('Record atualizado. '.apply_cmd('dns'));go('records&zone_id='.(int)$_POST['zone_id']);case 'del_record':$repo->deleteRecord((int)$_POST['id']);fl('Record removido. '.apply_cmd('dns'));go('records&zone_id='.(int)$_POST['zone_id']);case 'policy':Settings::set('ns_access_policy',($_POST['policy']??'allow_all')==='allowlist'?'allowlist':'allow_all');fl('Firewall atualizado. '.apply_cmd('firewall'));go('firewall');case 'add_ip':$repo->addAllowed($_POST['ip_cidr']??'',$_POST['description']??'');fl('IP/rede adicionado. '.apply_cmd('firewall'));go('firewall');case 'toggle_ip':$repo->toggleAllowed((int)$_POST['id'],(int)$_POST['active']===1);fl('IP/rede atualizado. '.apply_cmd('firewall'));go('firewall');case 'del_ip':$repo->deleteAllowed((int)$_POST['id']);fl('IP/rede removido. '.apply_cmd('firewall'));go('firewall');case 'apply_all':fl(apply_cmd('all'));go('dashboard');}}
if($page==='dashboard'){headx('Dashboard');$s=$repo->stats();$ls=(new LicenseService())->status(false);echo '<section class="grid stats">';card('Zonas',$s['zones'],'BIND authoritative');card('Bloqueios',$s['blocks'],'RPZ');card('Firewall',$s['policy']==='allow_all'?'Permitir todos':'Somente lista','porta 53');card('Licença',$ls['status'],$ls['message']);echo '</section><section class="panel"><h2>Ações</h2><form method="post"><input type="hidden" name="act" value="apply_all">'.Csrf::field().'<button class="primary">Aplicar DNS + IPTABLES agora</button></form></section><section class="panel"><h2>Portas</h2><div class="timeline"><div><b>53</b><p>BIND9 DNS/NS + RPZ.</p></div><div><b>80</b><p>Redirect dos sites bloqueados.</p></div><div><b>8087/89</b><p>Admin e banner.</p></div></div></section>';foot();exit;}
if($page==='blocks'){headx('Bloqueios');echo '<section class="panel"><h2>Adicionar bloqueio</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="add_block">'.Csrf::field().'<label>Domínio<input name="domain" required></label><label>Categoria<select name="category"><option>malware</option><option>phishing</option><option>botnet</option><option>custom</option></select></label><label>Ação<select name="action"><option value="redirect">Redirect para banner</option><option value="nxdomain">NXDOMAIN</option></select></label><label class="wide">Motivo<input name="reason"></label><button class="primary">Salvar</button></form></section><section class="panel"><h2>Lista</h2><table><tr><th>Domínio</th><th>Ação</th><th>Status</th><th>Hits</th><th></th></tr>';foreach($repo->blocks() as $b){$a=(int)$b['active']===1;echo '<tr><td><b>'.Security::e($b['domain']).'</b><br><small>'.Security::e($b['reason']).'</small></td><td>'.Security::e($b['action']).'</td><td><span class="badge '.($a?'on':'off').'">'.($a?'ativo':'inativo').'</span></td><td>'.(int)$b['hits'].'</td><td class="actions"><form method="post"><input type="hidden" name="act" value="toggle_block">'.Csrf::field().'<input type="hidden" name="id" value="'.$b['id'].'"><input type="hidden" name="active" value="'.($a?0:1).'"><button>'.($a?'Desativar':'Ativar').'</button></form><form method="post"><input type="hidden" name="act" value="del_block">'.Csrf::field().'<input type="hidden" name="id" value="'.$b['id'].'"><button class="danger">Excluir</button></form></td></tr>';}echo '</table></section>';foot();exit;}
if($page==='zones'){headx('Zonas DNS');echo '<section class="panel"><h2>Criar zona</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="add_zone">'.Csrf::field().'<label>Zona<input name="zone" placeholder="exemplo.com.br" required></label><label>TTL<input type="number" name="ttl" value="3600"></label><button class="primary">Criar</button></form></section><section class="panel"><h2>Zonas</h2><table><tr><th>Zona</th><th>TTL</th><th>Status</th><th></th></tr>';foreach($repo->zones() as $z){$a=(int)$z['active']===1;echo '<tr><td><b>'.Security::e($z['name']).'</b></td><td>'.$z['ttl'].'</td><td><span class="badge '.($a?'on':'off').'">'.($a?'ativa':'inativa').'</span></td><td class="actions"><a class="btn" href="/admin/?page=records&zone_id='.$z['id'].'">Records</a><form method="post"><input type="hidden" name="act" value="toggle_zone">'.Csrf::field().'<input type="hidden" name="id" value="'.$z['id'].'"><input type="hidden" name="active" value="'.($a?0:1).'"><button>'.($a?'Desativar':'Ativar').'</button></form><form method="post"><input type="hidden" name="act" value="del_zone">'.Csrf::field().'<input type="hidden" name="id" value="'.$z['id'].'"><button class="danger">Excluir</button></form></td></tr>';}echo '</table></section>';foot();exit;}
if($page==='records'){$zone=$repo->zone((int)($_GET['zone_id']??0)); if(!$zone) throw new RuntimeException('Zona não encontrada');headx('Records: '.$zone['name']);echo '<section class="panel"><h2>Novo record</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="add_record"><input type="hidden" name="zone_id" value="'.$zone['id'].'">'.Csrf::field().'<label>Nome<input name="name" value="@"></label><label>Tipo<select name="type"><option>A</option><option>AAAA</option><option>CNAME</option><option>MX</option><option>TXT</option><option>NS</option><option>SRV</option><option>CAA</option></select></label><label>TTL<input type="number" name="ttl" value="3600"></label><label class="wide">Conteúdo<input name="content" required></label><button class="primary">Salvar</button></form></section><section class="panel"><h2>Records</h2><table><tr><th>Nome</th><th>Tipo</th><th>TTL</th><th>Conteúdo</th><th>Status</th><th></th></tr>';foreach($repo->records((int)$zone['id']) as $r){$a=(int)$r['active']===1;echo '<tr><td>'.Security::e($r['name']).'</td><td>'.$r['type'].'</td><td>'.$r['ttl'].'</td><td>'.Security::e($r['content']).'</td><td><span class="badge '.($a?'on':'off').'">'.($a?'ativo':'inativo').'</span></td><td class="actions"><form method="post"><input type="hidden" name="act" value="toggle_record">'.Csrf::field().'<input type="hidden" name="zone_id" value="'.$zone['id'].'"><input type="hidden" name="id" value="'.$r['id'].'"><input type="hidden" name="active" value="'.($a?0:1).'"><button>'.($a?'Desativar':'Ativar').'</button></form><form method="post"><input type="hidden" name="act" value="del_record">'.Csrf::field().'<input type="hidden" name="zone_id" value="'.$zone['id'].'"><input type="hidden" name="id" value="'.$r['id'].'"><button class="danger">Excluir</button></form></td></tr>';}echo '</table></section>';foot();exit;}
if($page==='firewall'){headx('Firewall NS');$policy=Settings::get('ns_access_policy','allow_all');echo '<section class="panel alert"><h2>Controle de acesso ao DNS/NS</h2><p>Afeta somente TCP/UDP 53 via iptables/ip6tables.</p></section><section class="panel"><h2>Política</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="policy">'.Csrf::field().'<label class="wide">Modo<select name="policy"><option value="allow_all" '.($policy==='allow_all'?'selected':'').'>Permitir todos os IPs</option><option value="allowlist" '.($policy==='allowlist'?'selected':'').'>Bloquear todos, exceto lista</option></select></label><button class="primary">Salvar e aplicar</button></form><pre>'.Security::e(Settings::get('firewall_last_output','')).'</pre></section><section class="panel"><h2>Adicionar permitido</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="add_ip">'.Csrf::field().'<label>IP/CIDR<input name="ip_cidr" required placeholder="192.168.177.0/24"></label><label class="wide">Descrição<input name="description"></label><button class="primary">Adicionar</button></form></section><section class="panel"><h2>Lista</h2><table><tr><th>IP/CIDR</th><th>Descrição</th><th>Status</th><th></th></tr>';foreach($repo->allowed() as $ip){$a=(int)$ip['active']===1;echo '<tr><td><b>'.Security::e($ip['ip_cidr']).'</b></td><td>'.Security::e($ip['description']).'</td><td><span class="badge '.($a?'on':'off').'">'.($a?'ativo':'inativo').'</span></td><td class="actions"><form method="post"><input type="hidden" name="act" value="toggle_ip">'.Csrf::field().'<input type="hidden" name="id" value="'.$ip['id'].'"><input type="hidden" name="active" value="'.($a?0:1).'"><button>'.($a?'Desativar':'Ativar').'</button></form><form method="post"><input type="hidden" name="act" value="del_ip">'.Csrf::field().'<input type="hidden" name="id" value="'.$ip['id'].'"><button class="danger">Excluir</button></form></td></tr>';}echo '</table></section>';foot();exit;}
if($page==='settings'){headx('Configuração');$ls=(new LicenseService())->status(false);echo '<section class="panel"><h2>Configurações</h2><form class="form-grid" method="post"><input type="hidden" name="act" value="settings">'.Csrf::field().'<label>IP sinkhole<input name="sinkhole_ip" value="'.Security::e(Settings::get('sinkhole_ip','')).'"></label><label class="wide">URL redirect<input name="redirect_url" value="'.Security::e(Settings::get('redirect_url','')).'"></label><label class="wide">Licença<input name="license_key" value="'.Security::e(Settings::get('license_key','')).'"></label><label class="wide">URL validação<input name="license_url" value="'.Security::e(Settings::get('license_url','')).'"></label><label class="wide">Título aviso<input name="block_notice_title" value="'.Security::e(Settings::get('block_notice_title','')).'"></label><label class="wide">Mensagem<textarea name="block_notice_message">'.Security::e(Settings::get('block_notice_message','')).'</textarea></label><button class="primary">Salvar</button></form></section><section class="panel"><div class="panel-head"><h2>Licença</h2><form method="post"><input type="hidden" name="act" value="check_license">'.Csrf::field().'<button>Verificar agora</button></form></div><table><tr><th>Status</th><td>'.Security::e($ls['status']).'</td></tr><tr><th>Mensagem</th><td>'.Security::e($ls['message']).'</td></tr></table></section>';foot();exit;}
go('dashboard');}catch(Throwable $e){headx('Erro');echo '<section class="panel alert"><h2>Erro</h2><pre>'.Security::e($e->getMessage()).'</pre></section>';foot();}
